const crypto = require('crypto');

function decryptAes256Hex(cipherHex, passphrase) {
  const data = Buffer.from(cipherHex, 'hex');
  if (data.length < 17) throw new Error('Invalid ciphertext');

  const salt = data.subarray(0, 8);
  const iv = data.subarray(8, 16);
  const ciphertext = data.subarray(16);

  const keyIv = crypto.pbkdf2Sync(Buffer.from(passphrase, 'utf8'), salt, 100000, 48, 'sha256');
  const key = keyIv.subarray(0, 32);

  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
  const plaintext = Buffer.concat([decipher.update(ciphertext), decipher.final()]);
  return plaintext.toString('utf8');
}

