function parseCertificateSubject(subject) {
  const result = {};
  if (typeof subject !== 'string' || !subject) return result;

  let i = 0;
  while (i < subject.length) {
    if (subject[i] === '/') i++;
    let key = '';
    let value = '';
    while (i < subject.length && subject[i] !== '=') key += subject[i++];
    if (subject[i] !== '=') break;
    i++;
    while (i < subject.length && subject[i] !== '/') {
      if (subject[i] === '\\' && i + 1 < subject.length) {
        value += subject[i + 1];
        i += 2;
      } else {
        value += subject[i++];
      }
    }
    if (key) result[key] = value;
  }
  return result;
}

