function evaluateExpression(expr) {
  expr = String(expr).replace(/\s+/g, '');
  let i = 0;

  function parseExpression() {
    let value = parseTerm();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '+' && op !== '-') break;
      i++;
      const rhs = parseTerm();
      value = op === '+' ? value + rhs : value - rhs;
    }
    return value;
  }

  function parseTerm() {
    let value = parseFactor();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '*' && op !== '/') break;
      i++;
      const rhs = parseFactor();
      value = op === '*' ? value * rhs : value / rhs;
    }
    return value;
  }

  function parseFactor() {
    if (expr[i] === '+' || expr[i] === '-') {
      const sign = expr[i++] === '-' ? -1 : 1;
      return sign * parseFactor();
    }
    if (expr[i] === '(') {
      i++;
      const value = parseExpression();
      if (expr[i] === ')') i++;
      return value;
    }
    let start = i;
    while (i < expr.length && /[\d.]/.test(expr[i])) i++;
    return parseFloat(expr.slice(start, i));
  }

  return parseExpression();
} // END_SNIPPET

