export function createSecureTLSStreamPair() {
  // Create a self-signed certificate for testing
  const cert = `-----BEGIN CERTIFICATE-----
MIIBkTCB+wIJAKHHCgVZYYYAMA0GCSqGSIb3DQEBBQUAMBMxETAPBgNVBAMMCGxv
Y2FsaG9zdDAeFw0yMzAxMDEwMDAwMDBaFw0yNDAxMDEwMDAwMDBaMBMxETAPBgNV
BAMMCGxvY2FsaG9zdDBcMA0GCSqGSIb3DQEBAQUAA0sAMEgCQQDZ+DYlNB3Z8Z8K
