  const key = `-----BEGIN RSA PRIVATE KEY-----
MIIBOgIBAAJBANn4NiU0HdnxnwpZ+DYlNB3Z8Z8KZ+DYlNB3Z8Z8KZ+DYlNB3Z8Z
-----END RSA PRIVATE KEY-----`;

  // Create a pair of connected sockets
  const { socket1, socket2 } = net.createSocketPair();

  // Wrap socket1 with TLS (encrypted channel)
  const tlsStream = tls.connect({
    socket: socket1,
    rejectUnauthorized: false,
  });

  // Create a TLS server on socket2 (cleartext channel)
  const server = tls.createServer(
    {
      cert: cert,
      key: key,
    },
    (cleartextStream) => {
      // Handle the cleartext stream
      cleartextStream.on('data', (data) => {
        console.log('Server received:', data.toString());
      });
    }
  );

  // Connect the server to socket2
  server.emit('connection', socket2);

  return {
    encryptedStream: tlsStream,
    cleartextStream: socket2,
    server: server,
  };
}

