    super(props);
    this.state = {
      scrollPosition: 0,
      items: Array.from({ length: 50 }, (_, i) => `Item ${i + 1}`)
    };
  }

  getSnapshotBeforeUpdate(prevProps, prevState) {
    // Record scroll position before update
    const scrollPosition = window.scrollY || document.documentElement.scrollTop;
    console.log('Scroll position before update:', scrollPosition);
    return scrollPosition;
  }

  componentDidUpdate(prevProps, prevState, snapshot) {
    // snapshot contains the scroll position from getSnapshotBeforeUpdate
    if (snapshot !== null) {
      console.log('Recorded scroll position:', snapshot);
      this.setState({ scrollPosition: snapshot });
    }
  }

  addItem = () => {
    this.setState(prevState => ({
      items: [...prevState.items, `Item ${prevState.items.length + 1}`]
    }));
  };

  render() {
    return (
      <div style={{ padding: '20px' }}>
        <button onClick={this.addItem}>Add Item</button>
        <p>Current scroll position: {this.state.scrollPosition}px</p>
        <div style={{ height: '100vh', overflow: 'auto' }}>
          {this.state.items.map((item, index) => (
            <div key={index} style={{ padding: '10px', borderBottom: '1px solid #ccc' }}>
